);

import React, { useEffect, useState } from 'react';
import { BackgroundLights } from './components/BackgroundLights';
import { HeroContent } from './components/HeroContent';
import { Footer } from './components/Footer';

const App: React.FC = () => {
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    // Simulate initial asset loading for a smoother entrance
    const timer = setTimeout(() => {
      setIsLoaded(true);
    }, 500);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="relative min-h-screen w-full flex flex-col items-center justify-between overflow-hidden bg-[#050505] text-white selection:bg-amber-500/30">
      {/* Background Visuals */}
      <BackgroundLights />

      {/* Noise Overlay for texture */}
      <div className="pointer-events-none fixed inset-0 opacity-[0.03] z-10" style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}></div>

      {/* Main Layout */}
      <main className="relative z-20 flex-grow flex flex-col items-center justify-center w-full px-6 md:px-12">
        <HeroContent isLoaded={isLoaded} />
      </main>

      {/* Footer */}
      <Footer isLoaded={isLoaded} />

      {/* Vignette */}
      <div className="pointer-events-none fixed inset-0 z-30 bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.6)_100%)]"></div>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { motion } from 'framer-motion';

export const BackgroundLights: React.FC = () => {
  // Create 14 lights with random properties for organic movement
  const lights = useMemo(() => {
    return Array.from({ length: 14 }).map((_, i) => ({
      id: i,
      size: Math.random() * 300 + 100, // 100px to 400px
      x: Math.random() * 100, // 0% to 100%
      y: Math.random() * 100, // 0% to 100%
      duration: Math.random() * 20 + 10, // 10s to 30s
      delay: Math.random() * 5,
      opacity: Math.random() * 0.15 + 0.05, // 0.05 to 0.2
    }));
  }, []);

  return (
    <div className="fixed inset-0 overflow-hidden z-0">
      {lights.map((light) => (
        <motion.div
          key={light.id}
          className="absolute rounded-full blur-[80px] mix-blend-screen"
          style={{
            width: light.size,
            height: light.size,
            backgroundColor: light.id % 2 === 0 ? '#ffb700' : '#ffffff', // Amber and White mix
            top: `${light.y}%`,
            left: `${light.x}%`,
            opacity: light.opacity,
          }}
          animate={{
            x: [0, Math.random() * 100 - 50, Math.random() * 100 - 50, 0],
            y: [0, Math.random() * 100 - 50, Math.random() * 100 - 50, 0],
            scale: [1, 1.2, 0.9, 1],
            opacity: [light.opacity, light.opacity * 1.5, light.opacity * 0.8, light.opacity],
          }}
          transition={{
            duration: light.duration,
            repeat: Infinity,
            repeatType: "mirror",
            ease: "easeInOut",
            delay: light.delay,
          }}
        />
      ))}
      {/* A subtle central glow to highlight the content area */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-amber-500/5 rounded-full blur-[120px]" />
    </div>
  );
};

